const BASE_BLOCKED_ACTIONS = Object.freeze([
  "No live provider execution",
  "No real payment",
  "No real message, call, WhatsApp, or email send",
  "No appointment booking",
  "No pharmacy fulfillment",
  "No shipment tracking claim",
  "No drone dispatch",
  "No clinical referral submission"
]);

const DEFAULT_SAFETY_NOTES = Object.freeze([
  "Demo provider",
  "Local-safe test data",
  "Not live connected",
  "Provider credentials required for real execution"
]);

function provider(seed) {
  const id = seed.providerId;
  const name = seed.providerName;
  return Object.freeze({
    providerId: id,
    providerName: name,
    providerType: seed.providerType,
    serviceLane: seed.serviceLane,
    capabilities: seed.capabilities || [],
    supportedModes: seed.supportedModes || [],
    status: seed.status || "demo_available",
    readinessStatus: seed.readinessStatus || "local_only",
    demoOnly: true,
    testMode: true,
    liveConnected: false,
    configured: false,
    missingCredentials: seed.missingCredentials || seed.requiredCredentials || ["provider_credentials"],
    blockedActions: [...BASE_BLOCKED_ACTIONS, ...(seed.blockedActions || [])],
    availableLocalActions: seed.availableLocalActions || ["view demo provider", "prepare local packet", "save review note"],
    serviceArea: seed.serviceArea || "Demo region",
    contactPlaceholder: seed.contactPlaceholder || "Demo contact placeholder - not live connected",
    description: `${seed.description} This is a demo provider/local-safe test record, not a live connected provider.`,
    safetyNotes: [...DEFAULT_SAFETY_NOTES, ...(seed.safetyNotes || [])],
    exampleUseCases: seed.exampleUseCases || [],
    relatedWorkspaceIds: seed.relatedWorkspaceIds || [],
    createdAt: DEMO_TIMESTAMP,
    updatedAt: DEMO_TIMESTAMP,
    metadata: seed.metadata || {}
  });
}

