function getNexusDemoProviders() {
  return NEXUS_DEMO_PROVIDER_DATASET.map(item => ({ ...item }));
}

function summarizeDemoProviders(providers = getNexusDemoProviders()) {
  const laneMap = new Map();
  providers.forEach(item => {
    const lane = item.serviceLane;
    if (!laneMap.has(lane)) laneMap.set(lane, []);
    laneMap.get(lane).push(item);
  });
  const lanes = Array.from(laneMap.entries()).map(([serviceLane, records]) => ({
    serviceLane,
    count: records.length,
    sampleProviderNames: records.slice(0, 4).map(item => item.providerName),
    statuses: [...new Set(records.map(item => item.readinessStatus))],
    liveConnectedCount: records.filter(item => item.liveConnected).length,
    allDemoOnly: records.every(item => item.demoOnly && item.testMode && !item.liveConnected)
  })).sort((a, b) => a.serviceLane.localeCompare(b.serviceLane));
  return {
    totalProviders: providers.length,
    totalLanes: lanes.length,
    lanes,
    labels: ["Demo provider", "Local-safe test data", "Not live connected", "Provider credentials required for real execution"],
    noLiveExecution: providers.every(item => item.demoOnly && item.testMode && !item.liveConnected),
    generatedAt: new Date().toISOString()
  };
}

function getNexusDemoProviderCatalog() {
  const providers = getNexusDemoProviders();
  return {
    ok: true,
    provider: "nexus-demo-provider-dataset",
    status: "local_safe_demo_catalog",
    summary: summarizeDemoProviders(providers),
    providers,
    safety: {
      demoOnly: true,
      testMode: true,
      liveConnected: false,
      noRealProviderExecution: true,
      noPaymentsMoved: true,
      noMessagesSent: true,
      noAppointmentsBooked: true,
      noPharmacyFulfillment: true,
      noShipmentTrackingClaim: true,
      noDroneDispatch: true,
      noFakeCitations: true
    }
  };
}

module.exports = {
  NEXUS_DEMO_PROVIDER_DATASET,
  getNexusDemoProviders,
  summarizeDemoProviders,
  getNexusDemoProviderCatalog
};
